import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        try {
            // Simulate user input as a serialized object
            String userInput = "rO0ABXNyACJqYXZhLmxhbmcuU3RyaW5nO4v70Ml7zp0DAAB4cHBzcgATamF2YS5sYW5nLkludGVnZXIS4qCk94GhdAwABSQAEc2l6ZXhwAAAAAHhxAH4AAgE=";

            // Deserialize the object from user input
            ByteArrayInputStream bais = new ByteArrayInputStream(Base64.getDecoder().decode(userInput));
            ObjectInputStream ois = new ObjectInputStream(bais);
            Object obj = ois.readObject();

            // Print the deserialized object
            System.out.println("Deserialized object: " + obj);

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

